VALUES
  ('optician-moex-01609', 'optician', 'optician-moex-109-148c1cdf', 'sub-optician-04', NULL, 'single_choice', '有關調節幅度測量的推近法（push-upmethod）以及移遠法（pull-awaymethod）的敘述，下列何者正確？', '["推近法是先將近用視標放在患者眼前再慢慢向後移開（遠離患者）", "推近法測試常會因為患者對於模糊的理解與定義不同而造成結果有所差異", "移遠法的方式容易高估了患者的調節幅度", "採用推近法與移遠法的數據平均，是最適當的作法"]'::jsonb, 1, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T07:17:34+00:00", "source_pdf_sha1": "35cf199f6646", "answer_pdf_sha1": "a845aba7a8a1", "source_family": "moex-gov-tw", "moex": {"exam_code": "109110", "c": "113", "s": "1107", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "驗光學概要", "year": "109", "exam_name": "109年第二次專技人員高等考試中醫師考試分階段考試、營養師、心理師、護理師、社會工作師考試、109年專技人員高等考試法醫師、語言治療師、聽力...", "original_question_number": 43, "answer_corrected": false, "flags": [], "slug": "optician", "db_exam_id": "optician"}'::jsonb, NULL),
  ('optician-moex-01610', 'optician', 'optician-moex-109-148c1cdf', 'sub-optician-04', NULL, 'single_choice', '有關調節靈敏度（accommodativefacility）測試的敘述，下列何者錯誤？', '["測試距離通常為40公分，一般使用±2.00D翻轉鏡（flipper）", "翻轉鏡兩面提供的調節刺激（accommodativestimulus）分別為0.50D與4.50D", "成人的雙眼調節靈敏度期望值為每分鐘完成5次翻轉循環", "雙眼視覺異常者亦可能伴隨雙眼調節靈敏度低下"]'::jsonb, 2, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T07:17:34+00:00", "source_pdf_sha1": "35cf199f6646", "answer_pdf_sha1": "a845aba7a8a1", "source_family": "moex-gov-tw", "moex": {"exam_code": "109110", "c": "113", "s": "1107", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "驗光學概要", "year": "109", "exam_name": "109年第二次專技人員高等考試中醫師考試分階段考試、營養師、心理師、護理師、社會工作師考試、109年專技人員高等考試法醫師、語言治療師、聽力...", "original_question_number": 44, "answer_corrected": false, "flags": [], "slug": "optician", "db_exam_id": "optician"}'::jsonb, NULL),
  ('optician-moex-01611', 'optician', 'optician-moex-109-148c1cdf', 'sub-optician-04', NULL, 'single_choice', '一位受測者在20cm的閱讀距離可以認出的最小視標為20/50縮小史耐倫（reducedSnellen）視標，而在M 單位視力表最小能讀的字為1.0 M。最好呈現此近距離視力（near visual acuity）的紀錄為下列何種方', '["20/50", "0.2/1.0M", "20/50@20cm", "1.0M"]'::jsonb, 1, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T07:17:34+00:00", "source_pdf_sha1": "35cf199f6646", "answer_pdf_sha1": "a845aba7a8a1", "source_family": "moex-gov-tw", "moex": {"exam_code": "109110", "c": "113", "s": "1107", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "驗光學概要", "year": "109", "exam_name": "109年第二次專技人員高等考試中醫師考試分階段考試、營養師、心理師、護理師、社會工作師考試、109年專技人員高等考試法醫師、語言治療師、聽力...", "original_question_number": 45, "answer_corrected": false, "flags": [], "slug": "optician", "db_exam_id": "optician"}'::jsonb, NULL),
  ('optician-moex-01612', 'optician', 'optician-moex-109-148c1cdf', 'sub-optician-04', NULL, 'single_choice', '對 44～49 歲雙眼皆近視-0.50 DS 者進行老花眼驗光，下列何者是較適合標準檢測距離的暫時加入度 （tentativeadd）？', '["plano", "+0.75D", "+1.50D", "+2.00D"]'::jsonb, 1, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T07:17:34+00:00", "source_pdf_sha1": "35cf199f6646", "answer_pdf_sha1": "a845aba7a8a1", "source_family": "moex-gov-tw", "moex": {"exam_code": "109110", "c": "113", "s": "1107", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "驗光學概要", "year": "109", "exam_name": "109年第二次專技人員高等考試中醫師考試分階段考試、營養師、心理師、護理師、社會工作師考試、109年專技人員高等考試法醫師、語言治療師、聽力...", "original_question_number": 46, "answer_corrected": false, "flags": [], "slug": "optician", "db_exam_id": "optician"}'::jsonb, NULL),
  ('optician-moex-01613', 'optician', 'optician-moex-109-148c1cdf', 'sub-optician-04', NULL, 'single_choice', '有關負鏡片法（minuslensmethod）、推遠法（push-down）與推近法（push-up），此三種調節幅度測量法的 敘述，下列何者錯誤？', '["推遠法相對較易高估調節幅度", "推近法乃由遠至近，測量出第一個開始持續模糊的距離，與近點（nearpoint）實際位置有落差", "負鏡片法測得的調節幅度平均少於推近法所測數值2.00D", "施測推近法，若由患者自行手持視標，將測出較高調節幅度"]'::jsonb, 0, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T07:17:34+00:00", "source_pdf_sha1": "35cf199f6646", "answer_pdf_sha1": "a845aba7a8a1", "source_family": "moex-gov-tw", "moex": {"exam_code": "109110", "c": "113", "s": "1107", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "驗光學概要", "year": "109", "exam_name": "109年第二次專技人員高等考試中醫師考試分階段考試、營養師、心理師、護理師、社會工作師考試、109年專技人員高等考試法醫師、語言治療師、聽力...", "original_question_number": 47, "answer_corrected": false, "flags": [], "slug": "optician", "db_exam_id": "optician"}'::jsonb, NULL),
  ('optician-moex-01614', 'optician', 'optician-moex-109-148c1cdf', 'sub-optician-04', NULL, 'single_choice', '使用綜合驗光儀與±0.50D鏡片，為遠距屈光矯正後患者施測融像性交叉柱鏡（fusedcrosscylinder,FCC） 檢查，患者回報垂直線較為清晰。檢查者接著將±0.50 D鏡片移除，並放置負柱鏡軸在180度方向之傑克 森交叉圓柱鏡後，患者回報垂直線條較為清晰。此患者的檢查結果為下列何者？', '["調節遲滯（lagofaccommodation）", "垂直偏好（verticalpreference）", "調節過度（leadofaccommodation）", "檢查結果無法記錄"]'::jsonb, 1, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T07:17:34+00:00", "source_pdf_sha1": "35cf199f6646", "answer_pdf_sha1": "a845aba7a8a1", "source_family": "moex-gov-tw", "moex": {"exam_code": "109110", "c": "113", "s": "1107", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "驗光學概要", "year": "109", "exam_name": "109年第二次專技人員高等考試中醫師考試分階段考試、營養師、心理師、護理師、社會工作師考試、109年專技人員高等考試法醫師、語言治療師、聽力...", "original_question_number": 48, "answer_corrected": false, "flags": [], "slug": "optician", "db_exam_id": "optician"}'::jsonb, NULL),
  ('optician-moex-01615', 'optician', 'optician-moex-109-148c1cdf', 'sub-optician-04', NULL, 'single_choice', '於 33 公分工作距離，以動態檢影鏡單眼評估法（monocular estimation method）為患者檢查調節反應 （accommodative response），雙眼的檢查結果皆為MEM：+1.00 D。則患者在該檢測距離的調節反應為下 列何者？', '["1.50D", "2.00D", "2.50D", "3.00D"]'::jsonb, 1, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T07:17:34+00:00", "source_pdf_sha1": "35cf199f6646", "answer_pdf_sha1": "a845aba7a8a1", "source_family": "moex-gov-tw", "moex": {"exam_code": "109110", "c": "113", "s": "1107", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "驗光學概要", "year": "109", "exam_name": "109年第二次專技人員高等考試中醫師考試分階段考試、營養師、心理師、護理師、社會工作師考試、109年專技人員高等考試法醫師、語言治療師、聽力...", "original_question_number": 49, "answer_corrected": false, "flags": [], "slug": "optician", "db_exam_id": "optician"}'::jsonb, NULL),
  ('optician-moex-01616', 'optician', 'optician-moex-109-148c1cdf', 'sub-optician-04', NULL, 'single_choice', '使用負鏡片法檢測調節幅度（amplitudeofaccommodation）時，將近用視標擺放於33公分處，假設受檢者 遠距度數為OU-2.00DS，逐步加入-0.25DS，完成檢查後，綜合驗度儀上顯示的度數為-5.00DS，則此受 檢者的調節幅度最接近為何？', '["3.00D", "5.50D", "6.00D", "8.00D"]'::jsonb, 2, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T07:17:34+00:00", "source_pdf_sha1": "35cf199f6646", "answer_pdf_sha1": "a845aba7a8a1", "source_family": "moex-gov-tw", "moex": {"exam_code": "109110", "c": "113", "s": "1107", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "驗光學概要", "year": "109", "exam_name": "109年第二次專技人員高等考試中醫師考試分階段考試、營養師、心理師、護理師、社會工作師考試、109年專技人員高等考試法醫師、語言治療師、聽力...", "original_question_number": 50, "answer_corrected": false, "flags": [], "slug": "optician", "db_exam_id": "optician"}'::jsonb, NULL),
  ('optician-moex-01617', 'optician', 'optician-moex-108-5e38135e', 'sub-optician-01', NULL, 'single_choice', '下列何種先天性眼睛發育疾病常見的原因是妊娠期受到德國麻疹病毒影響而造成？', '["先天性色覺異常（congenital color blindness）", "先天性眼瞼下垂（congenital ptosis of the eyelid）", "先天性白內障（congenital cataracts）", "先天性無虹膜（congenital aniridia）"]'::jsonb, 2, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T07:17:34+00:00", "source_pdf_sha1": "0c0d680f512b", "answer_pdf_sha1": "e7890f56f712", "source_family": "moex-gov-tw", "moex": {"exam_code": "108060", "c": "402", "s": "0806", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "眼球構造與倫理法規概要", "year": "108", "exam_name": "108年專技人員高等考試大地工程技師考試分階段考試、驗船師、引水人、第一次食品技師考試、高等暨普通考試消防設備人員考試、普通考試地政士、專責...", "original_question_number": 1, "answer_corrected": false, "flags": [], "slug": "optician", "db_exam_id": "optician"}'::jsonb, NULL),
  ('optician-moex-01618', 'optician', 'optician-moex-108-5e38135e', 'sub-optician-01', NULL, 'single_choice', '下列有關眼瞼發育的敘述，何者錯誤？', '["胎兒在第3個月大時，上下眼瞼是保持融合的狀態", "直到大約7個月時眼瞼開始分開，其分離在出生之前才全部完成", "睫毛從表面外胚層發育而來，首先出現在上眼瞼", "眼輪匝肌（orbicularis oculi muscle）由第七對腦神經支配"]'::jsonb, 1, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T07:17:34+00:00", "source_pdf_sha1": "0c0d680f512b", "answer_pdf_sha1": "e7890f56f712", "source_family": "moex-gov-tw", "moex": {"exam_code": "108060", "c": "402", "s": "0806", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "眼球構造與倫理法規概要", "year": "108", "exam_name": "108年專技人員高等考試大地工程技師考試分階段考試、驗船師、引水人、第一次食品技師考試、高等暨普通考試消防設備人員考試、普通考試地政士、專責...", "original_question_number": 2, "answer_corrected": false, "flags": [], "slug": "optician", "db_exam_id": "optician"}'::jsonb, NULL)
